        $result | Should -Contain "backend"
    }
}

# ============================================================
# WORKFLOW STRUCTURE TESTS
# ============================================================

Describe "GitHub Actions Workflow Structure" {
    # These tests validate the workflow YAML file structure

    BeforeAll {
        $script:WorkflowPath = Join-Path $PSScriptRoot ".github/workflows/pr-label-assigner.yml"
    }

    It "workflow file exists" {
        Test-Path $script:WorkflowPath | Should -BeTrue
    }

    It "workflow YAML is valid (parseable)" {
        # Use PowerShell-yaml or basic YAML parsing
        # We'll read and check key patterns since PS doesn't have built-in YAML parsing
        $content = Get-Content $script:WorkflowPath -Raw
        $content | Should -Not -BeNullOrEmpty
    }

    It "workflow has push trigger" {
        $content = Get-Content $script:WorkflowPath -Raw
        $content | Should -Match "push:"
    }

    It "workflow has workflow_dispatch trigger" {
        $content = Get-Content $script:WorkflowPath -Raw
        $content | Should -Match "workflow_dispatch:"
    }

    It "workflow has at least one job" {
        $content = Get-Content $script:WorkflowPath -Raw
        $content | Should -Match "jobs:"
    }

    It "workflow uses actions/checkout@v4" {
        $content = Get-Content $script:WorkflowPath -Raw
        $content | Should -Match "actions/checkout@v4"
    }

    It "workflow references the script file" {
        $content = Get-Content $script:WorkflowPath -Raw
        $content | Should -Match "Invoke-PrLabelAssigner"
    }

    It "references to script files in workflow actually exist" {
        # Verify the script file referenced in workflow exists
        $scriptFile = Join-Path $PSScriptRoot "Invoke-PrLabelAssigner.ps1"
        Test-Path $scriptFile | Should -BeTrue
    }

    It "passes actionlint validation" {
