            return
        }
        $result = & actionlint $script:WorkflowPath 2>&1
        $LASTEXITCODE | Should -Be 0 -Because "actionlint should pass with no errors. Output: $result"
    }
}

# ============================================================
# ACT EXECUTION TESTS (End-to-end via Docker)
# ============================================================

Describe "Act Execution Tests" {
    # These tests run the workflow via `act` for each test fixture
    # Each test: creates temp git repo, runs act, captures output, asserts

    BeforeAll {
        # Locate act binary
        $script:ActPath = (Get-Command "act" -ErrorAction SilentlyContinue)?.Source
        if (-not $script:ActPath) {
            Write-Warning "act not found - Act Execution Tests will be skipped"
        }

        # Path to act-result.txt (in the workspace root)
        $script:ActResultFile = Join-Path $PSScriptRoot "act-result.txt"

        # Clear/initialize act-result.txt
        if (Test-Path $script:ActResultFile) {
            Remove-Item $script:ActResultFile -Force
        }

        # Define test cases (fixture data inline)
        $script:TestCases = @(
            @{
                Name            = "docs-only"
                Description     = "Documentation files get documentation label"
                ChangedFiles    = @("docs/README.md", "docs/guide.md")
                ExpectedLabels  = @("documentation")
                NotExpected     = @("api", "tests")
            },
            @{
                Name            = "api-files"
                Description     = "API source files get api and backend labels"
                ChangedFiles    = @("src/api/server.js", "src/api/routes.js")
                ExpectedLabels  = @("api", "backend")
                NotExpected     = @("documentation", "tests")
            },
            @{
                Name            = "test-files"
                Description     = "Test files get tests label"
                ChangedFiles    = @("src/app.test.js", "src/utils.test.ts")
                ExpectedLabels  = @("tests", "backend")
                NotExpected     = @("documentation", "api")
            },
            @{
                Name            = "mixed-changes"
                Description     = "Mixed PR with docs, api, and tests gets multiple labels"
                ChangedFiles    = @("docs/README.md", "src/api/server.js", "src/api/server.test.js")
                ExpectedLabels  = @("api", "tests", "documentation", "backend")
                NotExpected     = @()
            },
            @{
                Name            = "no-matches"
                Description     = "Files not matching any rule produce no labels"
                ChangedFiles    = @("random/unknown/file.xyz", "another/mystery.abc")
                ExpectedLabels  = @()
                NotExpected     = @("documentation", "api", "tests", "backend")
            }
        )
    }

    # Helper function to run a single act test case
    # Returns result hashtable with: ExitCode, Output, Labels
    function Invoke-ActTestCase {
        param(
            [hashtable]$TestCase,
            [string]$ActResultFile,
            [string]$ProjectRoot
        )

        # Create temp directory for this test case
        $tempDir = Join-Path ([System.IO.Path]::GetTempPath()) "pla-test-$($TestCase.Name)-$(Get-Random)"
        New-Item -ItemType Directory -Path $tempDir -Force | Out-Null

        try {
            # Copy all project files to temp dir
            $filesToCopy = @(
                "Invoke-PrLabelAssigner.ps1",
                "label-rules.json",
                ".github"
            )
            foreach ($item in $filesToCopy) {
                $src = Join-Path $ProjectRoot $item
                if (Test-Path $src) {
                    if ((Get-Item $src).PSIsContainer) {
                        Copy-Item -Recurse -Path $src -Destination $tempDir
                    } else {
                        Copy-Item -Path $src -Destination $tempDir
                    }
                }
            }

            # Create the changed-files.json fixture for this test case
            $changedFilesJson = $TestCase.ChangedFiles | ConvertTo-Json
            $changedFilesJson | Set-Content (Join-Path $tempDir "changed-files.json")

            # Initialize git repo
            Push-Location $tempDir
            & git init -b main 2>&1 | Out-Null
            & git config user.email "test@test.com" 2>&1 | Out-Null
            & git config user.name "Test" 2>&1 | Out-Null
            & git add -A 2>&1 | Out-Null
            & git commit -m "test: $($TestCase.Name)" 2>&1 | Out-Null
            Pop-Location

            # Run act
            $actOutput = & act push --rm `
                -W "$tempDir/.github/workflows/pr-label-assigner.yml" `
                --directory $tempDir `
                --no-cache-server `
                2>&1 | Out-String
            $actExitCode = $LASTEXITCODE

            # Append output to act-result.txt with delimiter
            $delimiter = "=" * 60
            $header = "`n$delimiter`nTEST CASE: $($TestCase.Name)`nDESCRIPTION: $($TestCase.Description)`n$delimiter`n"
            $footer = "`n$delimiter`nEXIT CODE: $actExitCode`n$delimiter`n"
            Add-Content -Path $ActResultFile -Value ($header + $actOutput + $footer)

            return @{
                ExitCode = $actExitCode
                Output   = $actOutput
            }
        } finally {
            if ($tempDir -and (Test-Path $tempDir)) {
                Remove-Item -Recurse -Force $tempDir -ErrorAction SilentlyContinue
            }
        }
    }

    It "act binary is available" {
        if (-not $script:ActPath) {
            Set-ItResult -Skipped -Because "act not installed"
        }
        $script:ActPath | Should -Not -BeNullOrEmpty
    }

    foreach ($testCase in @(
        @{
            Name            = "docs-only"
            Description     = "Documentation files get documentation label"
            ChangedFiles    = @("docs/README.md", "docs/guide.md")
            ExpectedLabels  = @("documentation")
            NotExpected     = @("api", "tests")
        },
        @{
            Name            = "api-files"
            Description     = "API source files get api and backend labels"
            ChangedFiles    = @("src/api/server.js", "src/api/routes.js")
            ExpectedLabels  = @("api", "backend")
            NotExpected     = @("documentation", "tests")
        },
        @{
            Name            = "test-files"
            Description     = "Test files get tests and backend labels"
            ChangedFiles    = @("src/app.test.js", "src/utils.test.ts")
            ExpectedLabels  = @("tests", "backend")
            NotExpected     = @("documentation", "api")
        },
        @{
            Name            = "mixed-changes"
            Description     = "Mixed PR gets multiple labels"
            ChangedFiles    = @("docs/README.md", "src/api/server.js", "src/api/server.test.js")
            ExpectedLabels  = @("api", "tests", "documentation", "backend")
            NotExpected     = @()
        },
        @{
            Name            = "no-matches"
            Description     = "Unmatched files produce no labels"
            ChangedFiles    = @("random/unknown/file.xyz")
            ExpectedLabels  = @()
            NotExpected     = @("documentation", "api", "tests", "backend")
        }
    )) {
        It "act: $($testCase.Name) - exits with code 0" -TestCases @{ tc = $testCase } {
            param($tc)
            if (-not $script:ActPath) { Set-ItResult -Skipped -Because "act not installed"; return }

            $result = Invoke-ActTestCase -TestCase $tc -ActResultFile $script:ActResultFile -ProjectRoot $PSScriptRoot
            $result.ExitCode | Should -Be 0 -Because "act should exit 0 for test case '$($tc.Name)'. Output:`n$($result.Output)"
        }

        It "act: $($testCase.Name) - job succeeded" -TestCases @{ tc = $testCase } {
            param($tc)
            if (-not $script:ActPath) { Set-ItResult -Skipped -Because "act not installed"; return }

            $result = Invoke-ActTestCase -TestCase $tc -ActResultFile $script:ActResultFile -ProjectRoot $PSScriptRoot
            $result.Output | Should -Match "Job succeeded" -Because "workflow job should succeed"
        }

        foreach ($expectedLabel in $testCase.ExpectedLabels) {
            It "act: $($testCase.Name) - output contains expected label '$expectedLabel'" -TestCases @{ tc = $testCase; label = $expectedLabel } {
                param($tc, $label)
                if (-not $script:ActPath) { Set-ItResult -Skipped -Because "act not installed"; return }

                $result = Invoke-ActTestCase -TestCase $tc -ActResultFile $script:ActResultFile -ProjectRoot $PSScriptRoot
                $result.Output | Should -Match "LABEL:.*$label" -Because "output should contain label '$label'"
            }
        }

        foreach ($notExpectedLabel in $testCase.NotExpected) {
            It "act: $($testCase.Name) - output does NOT contain label '$notExpectedLabel'" -TestCases @{ tc = $notExpectedLabel; label = $notExpectedLabel } {
                param($tc, $label)
                if (-not $script:ActPath) { Set-ItResult -Skipped -Because "act not installed"; return }

                $result = Invoke-ActTestCase -TestCase $tc -ActResultFile $script:ActResultFile -ProjectRoot $PSScriptRoot
                $result.Output | Should -Not -Match "LABEL:.*$label" -Because "output should NOT contain label '$label'"
            }
        }
    }

    It "act-result.txt file exists after act tests" {
        # This test runs after all act tests - verify the artifact was created
        if (-not $script:ActPath) { Set-ItResult -Skipped -Because "act not installed"; return }
        Test-Path $script:ActResultFile | Should -BeTrue -Because "act-result.txt must exist as a required artifact"
    }
}

