Describe "Act Execution Tests" {
    BeforeAll {
        # Locate act binary
        $script:ActPath = (Get-Command "act" -ErrorAction SilentlyContinue)?.Source

        # Path to act-result.txt output artifact
        $script:ActResultFile = Join-Path $PSScriptRoot "act-result.txt"

        # Clear/initialize act-result.txt
        if (Test-Path $script:ActResultFile) {
            Remove-Item $script:ActResultFile -Force
        }
        # Ensure the file exists even if act is unavailable
        New-Item -ItemType File -Path $script:ActResultFile -Force | Out-Null

        # Cache to store act results keyed by test case name
        # Populated once per test case; It blocks read from cache.
        $script:ActResultCache = @{}

        # Helper: run one act test case, return result hashtable
        function script:Invoke-ActTestCase {
            param([hashtable]$TestCase)

            $projectRoot = $PSScriptRoot

            # Create isolated temp directory for this test case
            $tempDir = Join-Path ([System.IO.Path]::GetTempPath()) "pla-$($TestCase.Name)-$(Get-Random)"
            New-Item -ItemType Directory -Path $tempDir -Force | Out-Null

            try {
                # Copy project files into temp dir
                foreach ($item in @("Invoke-PrLabelAssigner.ps1", "label-rules.json", ".github")) {
                    $src = Join-Path $projectRoot $item
                    if (Test-Path $src) {
                        $dest = $tempDir
                        if ((Get-Item $src).PSIsContainer) {
                            Copy-Item -Recurse -Path $src -Destination $dest
                        } else {
                            Copy-Item -Path $src -Destination $dest
                        }
                    }
                }

                # Write the fixture changed-files.json for this test case
                $TestCase.ChangedFiles | ConvertTo-Json | Set-Content (Join-Path $tempDir "changed-files.json")

                # Initialize a git repository (act requires a git repo for push events)
                Push-Location $tempDir
                & git init -b main 2>&1 | Out-Null
                & git config user.email "test@example.com" 2>&1 | Out-Null
                & git config user.name "Test Runner" 2>&1 | Out-Null
                & git add -A 2>&1 | Out-Null
                & git commit -m "test: $($TestCase.Name)" 2>&1 | Out-Null
                Pop-Location

                # Run act; capture stdout+stderr
                $actOutput = & act push --rm `
                    --directory $tempDir `
                    -W "$tempDir/.github/workflows/pr-label-assigner.yml" `
                    --no-cache-server `
                    2>&1 | Out-String
                $actExitCode = $LASTEXITCODE

                # Append to act-result.txt with clear delimiters
                $bar = "=" * 60
                $block = @"

$bar
TEST CASE: $($TestCase.Name)
DESCRIPTION: $($TestCase.Description)
$bar
$actOutput
EXIT CODE: $actExitCode
$bar

"@
                Add-Content -Path $script:ActResultFile -Value $block

                return @{
                    ExitCode = $actExitCode
                    Output   = $actOutput
                }
            } finally {
                Pop-Location -ErrorAction SilentlyContinue
                if ($tempDir -and (Test-Path $tempDir)) {
                    Remove-Item -Recurse -Force $tempDir -ErrorAction SilentlyContinue
                }
            }
        }

        # Run all test cases once and cache results (avoids re-running act per assertion)
        if ($script:ActPath) {
            foreach ($tc in $ActTestCases) {
                Write-Host "  [act] Running test case: $($tc.Name) ..."
                $script:ActResultCache[$tc.Name] = script:Invoke-ActTestCase -TestCase $tc
            }
        } else {
            Write-Warning "act not found - all Act Execution Tests will be skipped"
        }
    }

    It "act binary is available" {
        $script:ActPath | Should -Not -BeNullOrEmpty -Because "act must be installed to run workflow tests"
    }

    # --- Per-test-case assertions ---
    # The foreach loop runs during Pester Discovery so test case data must be
    # available at that time (defined at Describe scope above, not in BeforeAll).

    foreach ($tc in $ActTestCases) {
        It "act: $($tc.Name) - exits with code 0" -TestCases @{ tcName = $tc.Name; tcDesc = $tc.Description } {
            param($tcName, $tcDesc)
            if (-not $script:ActPath) { Set-ItResult -Skipped -Because "act not installed"; return }
            $r = $script:ActResultCache[$tcName]
            $r | Should -Not -BeNullOrEmpty -Because "cached result for '$tcName' should exist"
            $r.ExitCode | Should -Be 0 -Because "act should exit 0 for '$tcName'. Output:`n$($r.Output)"
        }

        It "act: $($tc.Name) - job succeeded" -TestCases @{ tcName = $tc.Name } {
            param($tcName)
            if (-not $script:ActPath) { Set-ItResult -Skipped -Because "act not installed"; return }
            $r = $script:ActResultCache[$tcName]
            $r.Output | Should -Match "Job succeeded" -Because "workflow job should succeed for '$tcName'"
        }

        foreach ($expectedLabel in $tc.ExpectedLabels) {
            It "act: $($tc.Name) - output contains 'LABEL: $expectedLabel'" `
                -TestCases @{ tcName = $tc.Name; lbl = $expectedLabel } {
                param($tcName, $lbl)
                if (-not $script:ActPath) { Set-ItResult -Skipped -Because "act not installed"; return }
                $r = $script:ActResultCache[$tcName]
                $r.Output | Should -Match "LABEL: $lbl" -Because "output should contain label '$lbl' for '$tcName'"
            }
        }

        foreach ($notExpected in $tc.NotExpected) {
            It "act: $($tc.Name) - output does NOT contain 'LABEL: $notExpected'" `
                -TestCases @{ tcName = $tc.Name; lbl = $notExpected } {
                param($tcName, $lbl)
                if (-not $script:ActPath) { Set-ItResult -Skipped -Because "act not installed"; return }
                $r = $script:ActResultCache[$tcName]
                $r.Output | Should -Not -Match "LABEL: $lbl" -Because "output should NOT contain label '$lbl' for '$tcName'"
            }
        }
    }

    It "act-result.txt file exists after all act tests" {
        Test-Path $script:ActResultFile | Should -BeTrue -Because "act-result.txt is a required artifact"
    }
}

