Describe "Get-PrLabels - Priority Conflict Resolution" {
    # TDD Iteration 4: explicit priority-based conflict tests

    It "uses highest priority when same label appears in multiple rules" {
        # Two rules both assign 'backend' label with different priorities
        $rules = @(
            @{ Pattern = "src/**"; Label = "backend"; Priority = 5 }
